    def get_dashboard(self) -> Dict[str, Any]:
        position_builder = self._apply_business_org_filter(self.db.query(RecruitmentPosition).filter(RecruitmentPosition.deleted.is_(False)), RecruitmentPosition)
        candidate_builder = self._apply_business_org_filter(self.db.query(RecruitmentCandidate).filter(RecruitmentCandidate.deleted.is_(False)), RecruitmentCandidate)
        positions = position_builder.all()
        candidates = candidate_builder.all()
        recent_candidates = candidate_builder.order_by(RecruitmentCandidate.created_at.desc(), RecruitmentCandidate.id.desc()).limit(8).all()
        today_start = datetime.now().replace(hour=0, minute=0, second=0, microsecond=0)
        tomorrow_start = today_start + timedelta(days=1)
        today_ai_task_count = (
            self.db.query(RecruitmentAITaskLog)
            .filter(
                RecruitmentAITaskLog.created_at >= today_start,
                RecruitmentAITaskLog.created_at < tomorrow_start,
            )
            .count()
        )
        distribution: Dict[str, int] = {}
        for candidate in candidates:
            distribution[candidate.status] = distribution.get(candidate.status, 0) + 1
        return {
            "cards": {
                "positions_total": len(positions),
                "positions_recruiting": len([item for item in positions if item.status == "recruiting"]),
                "candidates_total": len(candidates),
                "pending_screening": len([item for item in candidates if item.status == "pending_screening"]),
                "screening_passed": len(
                    [
                        item
                        for item in candidates
                        if item.status in {"screening_passed", "pending_interview", "interview_passed", "pending_offer", "offer_sent", "hired"}
                    ]
                ),
                "recent_ai_tasks": today_ai_task_count,
            },
            "status_distribution": [{"status": key, "count": value} for key, value in sorted(distribution.items(), key=lambda item: item[0])],
            "recent_candidates": [self._serialize_candidate_summary(item) for item in recent_candidates],
        }

    def list_positions(self, query: Optional[str] = None, status: Optional[str] = None) -> List[Dict[str, Any]]:
        builder = self._apply_business_org_filter(self.db.query(RecruitmentPosition).filter(RecruitmentPosition.deleted.is_(False)), RecruitmentPosition)
        if status:
            builder = builder.filter(RecruitmentPosition.status == status)
        if query:
            keyword = f"%{query.strip()}%"
            builder = builder.filter(or_(RecruitmentPosition.title.like(keyword), RecruitmentPosition.department.like(keyword), RecruitmentPosition.location.like(keyword), RecruitmentPosition.summary.like(keyword)))
        rows = builder.order_by(RecruitmentPosition.updated_at.desc(), RecruitmentPosition.id.desc()).all()
        if not rows:
            return []

        position_ids = [row.id for row in rows]
        skill_row_map = self._build_position_task_skill_row_map(rows)
        auto_mail_config_map = self._build_position_auto_mail_config_map(position_ids)
        active_jd_map, jd_version_count_map = self._build_position_jd_stats(rows)
        candidate_count_map = self._build_position_candidate_count_map(position_ids)
        bound_position_titles = {row.id: row.title for row in rows}
        return [
            self._serialize_position(
                row,
                _preloaded_skill_rows=skill_row_map[row.id],
                _preloaded_auto_mail_config=auto_mail_config_map[row.id],
                _preloaded_current_jd=active_jd_map[row.id],
                _preloaded_current_jd_loaded=True,
                _preloaded_jd_version_count=jd_version_count_map[row.id],
                _preloaded_candidate_count=candidate_count_map[row.id],
                _preloaded_bound_position_titles=bound_position_titles,
            )
            for row in rows
        ]

    @staticmethod
    def _normalize_position_title_for_unique(title: Any) -> str:
        return re.sub(r"\s+", " ", str(title or "").strip()).casefold()

    def _assert_position_title_unique_in_org(
        self,
        *,
        org_code: str,
        title: Any,
        exclude_position_id: Optional[int] = None,
    ) -> str:
        title_text = str(title or "").strip()
        normalized_title = self._normalize_position_title_for_unique(title_text)
        if not normalized_title:
            raise ValueError("岗位名称不能为空")
        normalized_org_code = normalize_org_code(org_code)
        rows = self.db.query(RecruitmentPosition).filter(
            RecruitmentPosition.deleted.is_(False),
            RecruitmentPosition.org_code == normalized_org_code,
        ).all()
        for row in rows:
            if exclude_position_id and int(row.id) == int(exclude_position_id):
                continue
            if self._normalize_position_title_for_unique(row.title) == normalized_title:
                raise ValueError(f"当前组织下已存在岗位「{row.title}」，请更换岗位名称。")
        return title_text

    def create_position(self, payload: Dict[str, Any], actor_id: str) -> Dict[str, Any]:
        org_code = normalize_org_code(payload.get("org_code") or self._current_org_code())
        self._assert_can_create_in_org(org_code)
        title = self._assert_position_title_unique_in_org(org_code=org_code, title=payload.get("title"))
        row = RecruitmentPosition(position_code=f"TMP-{uuid.uuid4().hex[:8]}", org_code=org_code, title=title, department=payload.get("department"), location=payload.get("location"), employment_type=payload.get("employment_type"), salary_range=payload.get("salary_range"), headcount=int(payload.get("headcount") or 1), key_requirements=payload.get("key_requirements"), bonus_points=payload.get("bonus_points"), summary=payload.get("summary"), status=payload.get("status") or "draft", auto_screen_on_upload=bool(payload.get("auto_screen_on_upload")), auto_advance_on_screening=payload.get("auto_advance_on_screening") is not False, jd_skill_ids_json=json_dumps_safe(_dedupe_ints(payload.get("jd_skill_ids") or [])), screening_skill_ids_json=json_dumps_safe(_dedupe_ints(payload.get("screening_skill_ids") or [])), interview_skill_ids_json=json_dumps_safe(_dedupe_ints(payload.get("interview_skill_ids") or [])), tags_json=json_dumps_safe(payload.get("tags") or []), created_by=actor_id, updated_by=actor_id, deleted=False)
        self.db.add(row)
        self.db.flush()
        row.position_code = f"POS-{row.id:05d}"
        self._sync_position_task_skill_bindings(
            row,
            actor_id=actor_id,
            jd_skill_ids=payload.get("jd_skill_ids") or [],
            screening_skill_ids=payload.get("screening_skill_ids") or [],
            interview_skill_ids=payload.get("interview_skill_ids") or [],
        )
        self._reconcile_bound_skills_for_position(row, actor_id=actor_id)
        auto_mail_config = self._normalize_position_auto_mail_config(payload)
        self._upsert_json_rule_config(
            POSITION_AUTO_MAIL_CONFIG_KEY,
            auto_mail_config,
            scope="position",
            scope_id=row.id,
            description="岗位级初筛自动邮件推送配置",
        )
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_position(row)

    def update_position(self, position_id: int, payload: Dict[str, Any], actor_id: str) -> Dict[str, Any]:
        row = self._get_position(position_id)
        if "title" in payload:
            payload = {
                **payload,
                "title": self._assert_position_title_unique_in_org(
                    org_code=normalize_org_code(getattr(row, "org_code", None)),
                    title=payload.get("title"),
                    exclude_position_id=row.id,
                ),
            }
        for field in ["title", "department", "location", "employment_type", "salary_range", "headcount", "key_requirements", "bonus_points", "summary", "status", "auto_screen_on_upload", "auto_advance_on_screening"]:
            if field in payload:
                setattr(row, field, payload.get(field))
        if "tags" in payload:
            row.tags_json = json_dumps_safe(payload.get("tags") or [])
        if any(field in payload for field in ["jd_skill_ids", "screening_skill_ids", "interview_skill_ids"]):
            self._sync_position_task_skill_bindings(
                row,
                actor_id=actor_id,
                jd_skill_ids=payload.get("jd_skill_ids") if "jd_skill_ids" in payload else None,
                screening_skill_ids=payload.get("screening_skill_ids") if "screening_skill_ids" in payload else None,
                interview_skill_ids=payload.get("interview_skill_ids") if "interview_skill_ids" in payload else None,
            )
            self._reconcile_bound_skills_for_position(row, actor_id=actor_id)
        auto_mail_payload_fields = {
            "auto_mail_enabled",
            "auto_mail_use_global_recipients",
            "auto_mail_use_position_recipients",
            "auto_mail_position_recipient_ids",
            "auto_mail_allowed_candidate_statuses",
            "auto_mail_template_id",
            "auto_mail_dedup_mode",
            "auto_mail_cc_recipient_ids",
            "auto_mail_bcc_recipient_ids",
        }
        if any(field in payload for field in auto_mail_payload_fields):
            merged_auto_mail_config = {
                **self._get_position_auto_mail_config(row.id),
                **{field: payload.get(field) for field in auto_mail_payload_fields if field in payload},
            }
            self._upsert_json_rule_config(
                POSITION_AUTO_MAIL_CONFIG_KEY,
                self._normalize_position_auto_mail_config(merged_auto_mail_config),
                scope="position",
                scope_id=row.id,
                description="岗位级初筛自动邮件推送配置",
            )
        row.updated_by = actor_id
        self.db.add(row)
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_position(row)

    def delete_position(self, position_id: int, actor_id: str) -> None:
        row = self._get_position(position_id)
        row.deleted = True
        row.updated_by = actor_id
        self.db.add(row)
        self.db.commit()

    def get_position_detail(self, position_id: int) -> Dict[str, Any]:
        row = self._get_position(position_id)
        jd_versions = self.db.query(RecruitmentJDVersion).filter(RecruitmentJDVersion.position_id == row.id).order_by(RecruitmentJDVersion.version_no.desc(), RecruitmentJDVersion.id.desc()).all()
        current_jd = self.db.query(RecruitmentJDVersion).filter(RecruitmentJDVersion.id == row.current_jd_version_id).first() if row.current_jd_version_id else None
        if not current_jd:
            current_jd = next((item for item in jd_versions if item.is_active), None)
        latest_log = self.db.query(RecruitmentAITaskLog).filter(RecruitmentAITaskLog.task_type == "jd_generation", RecruitmentAITaskLog.related_position_id == row.id).order_by(RecruitmentAITaskLog.created_at.desc(), RecruitmentAITaskLog.id.desc()).first()
        jd_generation = None if not latest_log else {"status": latest_log.status, "task_id": latest_log.id, "last_generated_at": isoformat_or_none(latest_log.updated_at or latest_log.created_at), "started_at": isoformat_or_none(latest_log.created_at), "error_message": latest_log.error_message, "model_provider": latest_log.model_provider, "model_name": latest_log.model_name}
        publish_tasks = self.db.query(RecruitmentPublishTask).filter(RecruitmentPublishTask.position_id == row.id).order_by(RecruitmentPublishTask.created_at.desc(), RecruitmentPublishTask.id.desc()).all()
        candidate_page = self.list_candidates(position_id=row.id, limit=20, offset=0, compact=True)
        return {"position": self._serialize_position(row), "current_jd_version": self._serialize_jd_version(current_jd) if current_jd else None, "jd_versions": [self._serialize_jd_version(item) for item in jd_versions], "jd_generation": jd_generation, "publish_tasks": [self._serialize_publish_task(item) for item in publish_tasks], "candidates": candidate_page.get("items", [])}

    def list_skills(
        self,
        *,
        query: Optional[str] = None,
        task_type: Optional[str] = None,
        org_codes: Optional[Sequence[str]] = None,
        limit: int = 0,
        offset: int = 0,
        summary: bool = False,
    ) -> Any:
        normalized_query = str(query or "").strip().lower()
        normalized_task_type = str(task_type or "").strip()
        normalized_org_codes = normalize_org_code_list(org_codes or [])
        requested_limit = max(0, int(limit or 0))
        safe_offset = max(0, int(offset or 0))
        is_legacy_full_list = not (
            summary
            or normalized_query
            or normalized_task_type
            or normalized_org_codes
            or requested_limit
            or safe_offset
        )

        if is_legacy_full_list:
            rows = (
                self.db.query(RecruitmentSkill)
                .filter(RecruitmentSkill.deleted.is_(False))
                .order_by(
                    RecruitmentSkill.sort_order.asc(),
                    RecruitmentSkill.created_at.desc(),
                    RecruitmentSkill.id.desc(),
                )
                .all()
            )
            visible_rows = [row for row in rows if self._can_access_org_resource(row)]
            bound_position_ids = {
                int(row.bound_position_id)
                for row in visible_rows
                if getattr(row, "bound_position_id", None)
            }
            bound_position_titles = {
                int(position_id): title
                for position_id, title in (
                    self.db.query(RecruitmentPosition.id, RecruitmentPosition.title)
                    .filter(
                        RecruitmentPosition.id.in_(bound_position_ids),
                        RecruitmentPosition.deleted.is_(False),
                    )
                    .all()
                    if bound_position_ids else []
                )
            }
            return [
                self._serialize_skill(
                    row,
                    _preloaded_bound_position_titles=bound_position_titles,
                )
                for row in visible_rows
            ]

        safe_limit = requested_limit or 50
        builder = self.db.query(RecruitmentSkill).filter(RecruitmentSkill.deleted.is_(False))
        organization_paths: Dict[str, str] = {}

        if self.permission_context and not self.permission_context.has_all_orgs:
            visible_org_codes = {
                normalize_org_code(org_code)
                for org_code in (self.permission_context.visible_org_codes or ())
            }
            organization_paths = self._get_active_org_paths()
            visible_paths = {
                organization_paths.get(org_code, "")
                for org_code in visible_org_codes
                if organization_paths.get(org_code, "")
            }
            ancestor_org_codes = {
                org_code
                for org_code, org_path in organization_paths.items()
                if org_path and any(
                    visible_path == org_path or visible_path.startswith(f"{org_path}/")
                    for visible_path in visible_paths
                )
            }
            builder = builder.filter(or_(
                func.upper(func.coalesce(RecruitmentSkill.scope_level, "")) == "GLOBAL",
                func.upper(func.coalesce(RecruitmentSkill.share_policy, "")) == SHARE_POLICY_PUBLIC_IN_GROUP,
                RecruitmentSkill.org_code.in_(visible_org_codes),
                and_(
                    RecruitmentSkill.allow_sub_org_use.is_(True),
                    func.upper(func.coalesce(RecruitmentSkill.share_policy, "")).in_([
                        SHARE_POLICY_SHARED_READONLY,
                        SHARE_POLICY_SHARED_COPYABLE,
                    ]),
                    RecruitmentSkill.org_code.in_(ancestor_org_codes),
                ),
            ))

        if normalized_org_codes:
            if not organization_paths:
                organization_paths = self._get_active_org_paths()
            target_paths = {
                organization_paths.get(org_code, "")
                for org_code in normalized_org_codes
                if organization_paths.get(org_code, "")
            }
            ancestor_org_codes = {
                org_code
                for org_code, org_path in organization_paths.items()
                if org_path and any(
                    target_path == org_path or target_path.startswith(f"{org_path}/")
                    for target_path in target_paths
                )
            }
            builder = builder.filter(or_(
                RecruitmentSkill.org_code.in_(normalized_org_codes),
                func.upper(func.coalesce(RecruitmentSkill.scope_level, "")) == "GLOBAL",
                func.upper(func.coalesce(RecruitmentSkill.share_policy, "")) == SHARE_POLICY_PUBLIC_IN_GROUP,
                and_(
                    RecruitmentSkill.allow_sub_org_use.is_(True),
                    RecruitmentSkill.org_code.in_(ancestor_org_codes),
                ),
            ))

        if normalized_query:
            escaped_query = (
                normalized_query
                .replace("\\", "\\\\")
                .replace("%", "\\%")
                .replace("_", "\\_")
            )
            search_pattern = f"%{escaped_query}%"
            builder = builder.outerjoin(
                RecruitmentPosition,
                and_(
                    RecruitmentPosition.id == RecruitmentSkill.bound_position_id,
                    RecruitmentPosition.deleted.is_(False),
                ),
            ).filter(or_(
                func.lower(func.coalesce(RecruitmentSkill.name, "")).like(search_pattern, escape="\\"),
                func.lower(func.coalesce(RecruitmentSkill.description, "")).like(search_pattern, escape="\\"),
                func.lower(func.coalesce(RecruitmentSkill.tags_json, "")).like(search_pattern, escape="\\"),
                func.lower(func.coalesce(RecruitmentPosition.title, "")).like(search_pattern, escape="\\"),
            ))

        ordered = builder.order_by(
            RecruitmentSkill.updated_at.desc(),
            RecruitmentSkill.created_at.desc(),
            RecruitmentSkill.sort_order.asc(),
            RecruitmentSkill.id.desc(),
        )
        if normalized_task_type:
            legacy_content = case(
                (
                    or_(
                        RecruitmentSkill.task_types_json.is_(None),
                        func.trim(RecruitmentSkill.task_types_json).in_(["", "[]", "null"]),
                    ),
                    RecruitmentSkill.content,
                ),
                else_=None,
            ).label("legacy_content")
            candidates = ordered.with_entities(
                RecruitmentSkill.id,
                RecruitmentSkill.skill_code,
                RecruitmentSkill.name,
                RecruitmentSkill.tags_json,
                RecruitmentSkill.task_types_json,
                RecruitmentSkill.skill_group,
                RecruitmentSkill.version,
                legacy_content,
            ).all()
            matching_ids = []
            for candidate in candidates:
                stored_task_types = json_loads_safe(candidate.task_types_json, [])
                runtime_meta = _extract_skill_runtime_meta({
                    "id": candidate.id,
                    "skill_code": candidate.skill_code,
                    "name": candidate.name,
                    "tags": json_loads_safe(candidate.tags_json, []),
                    "task_types": stored_task_types if isinstance(stored_task_types, list) else [],
                    "skill_group": candidate.skill_group,
                    "version": candidate.version,
                    "content": candidate.legacy_content or "",
                })
                if normalized_task_type in (runtime_meta.get("tasks") or []):
                    matching_ids.append(int(candidate.id))
            total = len(matching_ids)
            page_ids = matching_ids[safe_offset:safe_offset + safe_limit]
            page_rows_by_id = {
                int(row.id): row
                for row in self.db.query(RecruitmentSkill)
                .filter(RecruitmentSkill.id.in_(page_ids))
                .all()
            } if page_ids else {}
            visible_rows = [page_rows_by_id[skill_id] for skill_id in page_ids if skill_id in page_rows_by_id]
        else:
            total = int(
                builder.order_by(None)
                .with_entities(func.count(RecruitmentSkill.id))
                .scalar()
                or 0
            )
            visible_rows = ordered.offset(safe_offset).limit(safe_limit).all()

        bound_position_ids = {
            int(row.bound_position_id)
            for row in visible_rows
            if getattr(row, "bound_position_id", None)
        }
        bound_position_titles = {
            int(position_id): title
            for position_id, title in (
                self.db.query(RecruitmentPosition.id, RecruitmentPosition.title)
                .filter(
                    RecruitmentPosition.id.in_(bound_position_ids),
                    RecruitmentPosition.deleted.is_(False),
                )
                .all()
                if bound_position_ids else []
            )
        }
        items = [
            self._serialize_skill(
                row,
                _preloaded_bound_position_titles=bound_position_titles,
                summary=summary,
            )
            for row in visible_rows
        ]
        return {"items": items, "total": int(total or 0), "limit": safe_limit, "offset": safe_offset}

    def get_skill_detail(self, skill_id: int) -> Dict[str, Any]:
        return self._serialize_skill(self._get_skill(skill_id))

    def create_skill(self, payload: Dict[str, Any], actor_id: str) -> Dict[str, Any]:
        meta = _extract_skill_runtime_meta(payload)
        org_code = normalize_org_code(payload.get("org_code") or self._current_org_code())
        self._assert_can_create_in_org(org_code)
        task_types = payload.get("task_types") or []
        bound_position_id = payload.get("bound_position_id")
        if bound_position_id:
            self._get_position(int(bound_position_id))
        row = RecruitmentSkill(skill_code=f"skill-{_slugify(str(payload.get('name') or 'skill'))}-{uuid.uuid4().hex[:4]}", org_code=org_code, scope_level=str(payload.get("scope_level") or "ORG").strip().upper() or "ORG", share_policy=normalize_share_policy(payload.get("share_policy")), allow_sub_org_use=bool(payload.get("allow_sub_org_use")), allow_copy=bool(payload.get("allow_copy")), is_system_base=False, name=str(payload.get("name") or "").strip(), description=payload.get("description"), skill_group=str(payload.get("skill_group") or meta.get("group") or "").strip() or None, version=str(payload.get("version") or meta.get("version") or "").strip() or None, content=str(payload.get("content") or "").strip(), tags_json=json_dumps_safe(payload.get("tags") or []), task_types_json=json_dumps_safe(task_types) if task_types else None, bound_position_id=int(bound_position_id) if bound_position_id else None, sort_order=int(payload.get("sort_order") or 99), is_enabled=payload.get("is_enabled") is not False, created_by=actor_id, updated_by=actor_id, deleted=False)
        self.db.add(row)
        self.db.flush()
        self._sync_skill_bound_position_assignment(row, actor_id=actor_id)
        for position_id in {getattr(row, "bound_position_id", None)}:
            if position_id:
                self._reconcile_bound_skills_for_position(self._get_position(int(position_id)), actor_id=actor_id)
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_skill(row)

    def generate_skill_content_stream(self, role_name: str, extra_requirements: str, position_jd: str, on_delta: Callable[[str], None], actor_id: str = "unknown", on_task_created: Optional[Callable[[int], None]] = None) -> Dict[str, Any]:
        def extract_generated_text(value: Any) -> str:
            if isinstance(value, str):
                return value.strip()
            if isinstance(value, dict):
                for key in ("markdown", "text", "content"):
                    extracted = extract_generated_text(value.get(key))
                    if extracted:
                        return extracted
                html = value.get("html")
                if isinstance(html, str) and html.strip():
                    return strip_markdown(html.replace("<br />", "\n").replace("<br/>", "\n").replace("<br>", "\n")).strip()
            return ""

        user_prompt = f"岗位名称：{role_name}"
        if position_jd:
            user_prompt += f"\n\n岗位 JD 原文如下：\n{position_jd}"
        if extra_requirements:
            user_prompt += f"\n\n补充评估条件：{extra_requirements}"
        user_prompt += "\n\n请根据以上信息生成完整的初筛评分评估方案，维度总分必须恰好 10.0 分。每个维度的评估说明要具体、可操作，明确指出看什么证据。"
        request_hash = self._build_request_hash("skill_content_generation", 0, user_prompt, [])
        log_row = self._create_ai_task_log("skill_content_generation", created_by=actor_id, request_hash=request_hash)
        if on_task_created:
            on_task_created(log_row.id)
        control = RecruitmentTaskControl(log_row.id)
        recruitment_task_registry.register(log_row.id, control)
        resolved_runtime = None
        try:
            resolved_runtime = self.ai_gateway.resolve_config("skill_content_generation")
            if not resolved_runtime.api_key:
                raise ValueError("未配置 AI 模型，请先在「模型配置」中添加可用的 LLM 配置。")
            self._update_ai_task_log(log_row, status="running", provider=resolved_runtime.provider, model_name=resolved_runtime.model_name, model_source=resolved_runtime.source, prompt_snapshot=f"SYSTEM:\n{SKILL_GENERATION_SYSTEM_PROMPT}\n\nUSER:\n{user_prompt}", input_summary=truncate_text(user_prompt, 600), output_summary="正在生成 Skill 内容")
            result = self.ai_gateway.stream_text(
                task_type="skill_content_generation",
                system_prompt=SKILL_GENERATION_SYSTEM_PROMPT,
                user_prompt=user_prompt,
                on_delta=on_delta,
                cancel_control=control,
                runtime_config=resolved_runtime,
            )
            generated_text = extract_generated_text(result.get("content"))
            if not generated_text:
                raise RuntimeError("模型返回空内容，未生成有效文本")
            self._finish_ai_task_log(log_row, status="success", provider=result.get("provider"), model_name=result.get("model_name"), model_source=result.get("source"), prompt_snapshot=result.get("prompt_snapshot"), full_request_snapshot=result.get("full_request_snapshot"), input_summary=result.get("input_summary"), output_summary=truncate_text(generated_text, 600), output_snapshot={"content": result.get("content")}, token_usage=result.get("token_usage"))
            return result
        except RecruitmentTaskCancelled:
            self._finish_ai_task_log(log_row, status="cancelled", error_message="用户已停止生成", output_summary="已停止生成")
            raise
        except ValueError:
            self._finish_ai_task_log(log_row, status="failed", error_message="未配置 AI 模型")
            raise
        except Exception as exc:
            self._finish_ai_task_log(log_row, status="failed", provider=getattr(resolved_runtime, "provider", None) if resolved_runtime else None, model_name=getattr(resolved_runtime, "model_name", None) if resolved_runtime else None, error_message=str(exc), output_summary="生成失败")
            raise
        finally:
            recruitment_task_registry.pop(log_row.id)

    def update_skill(self, skill_id: int, payload: Dict[str, Any], actor_id: str) -> Dict[str, Any]:
        row = self._get_skill(skill_id)
        self._assert_resource_manageable(row, actor_id)
        previous_position_id = getattr(row, "bound_position_id", None)
        for field in ["name", "description", "content", "sort_order", "is_enabled", "scope_level", "allow_sub_org_use", "allow_copy"]:
            if field in payload:
                setattr(row, field, payload.get(field))
        if "share_policy" in payload:
            row.share_policy = normalize_share_policy(payload.get("share_policy"))
        if "org_code" in payload:
            next_org_code = normalize_org_code(payload.get("org_code"))
            self._assert_can_create_in_org(next_org_code)
            row.org_code = next_org_code
        if "tags" in payload:
            row.tags_json = json_dumps_safe(payload.get("tags") or [])
        if "task_types" in payload:
            task_types = payload.get("task_types") or []
            row.task_types_json = json_dumps_safe(task_types) if task_types else None
        if "bound_position_id" in payload:
            bound_position_id = payload.get("bound_position_id")
            if bound_position_id:
                self._get_position(int(bound_position_id))
                row.bound_position_id = int(bound_position_id)
            else:
                row.bound_position_id = None
        runtime_meta = _extract_skill_runtime_meta(
            {
                "skill_code": row.skill_code,
                "name": payload.get("name") if "name" in payload else row.name,
                "description": payload.get("description") if "description" in payload else row.description,
                "content": payload.get("content") if "content" in payload else row.content,
                "tags": payload.get("tags") if "tags" in payload else json_loads_safe(row.tags_json, []),
                "skill_group": payload.get("skill_group") if "skill_group" in payload else row.skill_group,
                "version": payload.get("version") if "version" in payload else row.version,
            }
        )
        if "skill_group" in payload or "content" in payload or "tags" in payload:
            row.skill_group = str(payload.get("skill_group") or runtime_meta.get("group") or "").strip() or None
        if "version" in payload or "content" in payload or "tags" in payload:
            row.version = str(payload.get("version") or runtime_meta.get("version") or "").strip() or None
        row.updated_by = actor_id
        self.db.add(row)
        self.db.flush()
        self._sync_skill_bound_position_assignment(row, actor_id=actor_id, previous_position_id=previous_position_id)
        for position_id in {previous_position_id, getattr(row, "bound_position_id", None)}:
            if position_id:
                self._reconcile_bound_skills_for_position(self._get_position(int(position_id)), actor_id=actor_id)
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_skill(row)

    def copy_skill(self, skill_id: int, actor_id: str, target_org_code: Optional[str] = None) -> Dict[str, Any]:
        source = self._get_skill(skill_id)
        self._assert_resource_copyable(source)
        org_code = normalize_org_code(target_org_code or self._current_org_code())
        self._assert_can_create_in_org(org_code)
        row = RecruitmentSkill(
            skill_code=f"skill-{_slugify(str(source.name or 'skill'))}-{uuid.uuid4().hex[:4]}",
            org_code=org_code,
            scope_level="ORG",
            share_policy="PRIVATE",
            allow_sub_org_use=False,
            allow_copy=False,
            is_system_base=False,
            name=f"{source.name} Copy",
            description=source.description,
            skill_group=source.skill_group,
            version=source.version,
            content=source.content,
            tags_json=source.tags_json,
            sort_order=source.sort_order,
            is_enabled=bool(source.is_enabled),
            created_by=actor_id,
            updated_by=actor_id,
            deleted=False,
        )
        self.db.add(row)
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_skill(row)

    def delete_skill(self, skill_id: int, actor_id: str) -> None:
        row = self._get_skill(skill_id)
        self._assert_resource_manageable(row, actor_id)
        row.deleted = True
        row.updated_by = actor_id
        self.db.add(row)
        self.db.commit()

    def toggle_skill(self, skill_id: int, enabled: bool, actor_id: str) -> Dict[str, Any]:
        row = self._get_skill(skill_id)
        self._assert_resource_manageable(row, actor_id)
        row.is_enabled = bool(enabled)
        row.updated_by = actor_id
        self.db.add(row)
        self.db.commit()
        self.db.refresh(row)
        return self._serialize_skill(row)
    def _serialize_parse_result(self, row: RecruitmentResumeParseResult, *, compact: bool = False) -> Dict[str, Any]:
        parsed_resume = {
            "basic_info": json_loads_safe(row.basic_info_json, {}),
            "work_experiences": json_loads_safe(row.work_experiences_json, []),
            "education_experiences": json_loads_safe(row.education_experiences_json, []),
            "skills": json_loads_safe(row.skills_json, []),
            "projects": json_loads_safe(row.projects_json, []),
            "summary": row.summary_text,
        }
        payload = {
            "id": row.id,
            "candidate_id": row.candidate_id,
            "resume_file_id": row.resume_file_id,
            "raw_text": row.raw_text or "",
            **parsed_resume,
            "status": row.status,
            "error_message": row.error_message,
            "created_at": isoformat_or_none(row.created_at),
        }
        if compact:
            payload["raw_text"] = _truncate_utf8_text(payload.get("raw_text"), CANDIDATE_DETAIL_JSON_PREVIEW_BYTES)
            payload["basic_info"] = _compact_candidate_detail_value(payload.get("basic_info"), max_items=12)
            payload["work_experiences"] = _compact_candidate_detail_value(payload.get("work_experiences"))
            payload["education_experiences"] = _compact_candidate_detail_value(payload.get("education_experiences"))
            payload["skills"] = _compact_candidate_detail_value(payload.get("skills"))
            payload["projects"] = _compact_candidate_detail_value(payload.get("projects"))
            payload["summary"] = _truncate_utf8_text(payload.get("summary"), CANDIDATE_DETAIL_TEXT_PREVIEW_BYTES)
        return payload

    def _serialize_score(self, row: RecruitmentCandidateScore) -> Dict[str, Any]:
        payload = json_loads_safe(row.score_json, {})
        if isinstance(payload, dict) and payload.get("_storage_format") == RAW_SCREENING_SCORE_STORAGE_FORMAT:
            raw_score = payload.get("score") if isinstance(payload.get("score"), dict) else {}
            debug_payload = payload.get("debug") if isinstance(payload.get("debug"), dict) else {}
            row_total_score = _parse_score_number(row.total_score)
            row_match_percent = _parse_score_number(row.match_percent)
            return {
                "id": row.id,
                "candidate_id": row.candidate_id,
                "parse_result_id": row.parse_result_id,
                "total_score": row_total_score if row_total_score is not None else raw_score.get("total_score"),
                "total_score_scale": 10,
                "match_percent": row_match_percent if row_match_percent is not None else raw_score.get("match_percent"),
                "advantages": _normalize_score_text_items(raw_score.get("advantages"), limit=5),
                "concerns": _normalize_score_text_items(raw_score.get("concerns"), limit=5),
                "recommendation": row.recommendation if row.recommendation is not None else raw_score.get("recommendation"),
                "suggested_status": _normalize_suggested_status(row.suggested_status or raw_score.get("suggested_status")) or row.suggested_status or raw_score.get("suggested_status"),
                "dimensions": sanitize_dimensions(raw_score.get("dimensions"), SCREENING_PAYLOAD_SCHEMA_CONFIG.get("score") or {}),
                "radar_scores": _sanitize_radar_scores(raw_score.get("radar_scores")),
                "score_validation_passed": debug_payload.get("score_validation_passed"),
                "validation_warnings": _normalize_score_warning_items(debug_payload.get("validation_warnings"), limit=8),
                "manual_override_score": row.manual_override_score,
                "manual_override_reason": row.manual_override_reason,
                "hr_feedback": row.hr_feedback,
                "hr_feedback_reason": row.hr_feedback_reason,
                "created_at": isoformat_or_none(row.created_at),
                "updated_at": isoformat_or_none(row.updated_at),
            }
        normalized_score = payload.get("normalized_score") if isinstance(payload.get("normalized_score"), dict) else None
        score_enhancements = payload.get("score_enhancements") if isinstance(payload.get("score_enhancements"), dict) else None
        if normalized_score is None:
            normalized_score = _shape_resume_score_payload(payload)
        if score_enhancements is None:
            score_enhancements = {
                "dimensions": _normalize_score_dimensions(payload.get("dimensions"), limit=12),
                "dimensions_mode": payload.get("dimensions_mode"),
                "missing_core_labels": list(payload.get("missing_core_labels") or []),
                "score_cap_reason": payload.get("score_cap_reason"),
                "derived_total_score_from_dimensions": _parse_score_number(payload.get("derived_total_score_from_dimensions")),
                "derived_match_percent_from_dimensions": _parse_score_number(payload.get("derived_match_percent_from_dimensions")),
                "score_quality_warnings": _normalize_score_warning_items(payload.get("score_quality_warnings"), limit=8),
                "repair_reason": payload.get("repair_reason"),
                "report_markdown": str(payload.get("report_markdown") or "").strip() or None,
                "risk_flags": list(payload.get("risk_flags") or []),
                "decision_note": payload.get("decision_note"),
                "score_source": payload.get("score_source"),
            }
        if score_enhancements.get("score_source") == "fallback_builder":
            score_enhancements["score_quality_warnings"] = _merge_warning_items(
                ["当前评分来自 fallback_builder，非主模型直接结构化结果"],
                score_enhancements.get("score_quality_warnings"),
                limit=8,
            )
        compatibility_score = _build_score_compat_payload(normalized_score, score_enhancements)
        row_total_score = _parse_score_number(row.total_score)
        row_match_percent = _parse_score_number(row.match_percent)
        return {
            "id": row.id,
            "candidate_id": row.candidate_id,
            "parse_result_id": row.parse_result_id,
            "total_score": row_total_score if row_total_score is not None else compatibility_score.get("total_score"),
            "total_score_scale": _infer_score_scale(row_total_score if row_total_score is not None else compatibility_score.get("total_score")),
            "match_percent": row_match_percent if row_match_percent is not None else compatibility_score.get("match_percent"),
            "advantages": _normalize_score_text_items(compatibility_score.get("advantages"), limit=5),
            "concerns": _normalize_score_text_items(compatibility_score.get("concerns"), limit=5),
            "recommendation": row.recommendation or compatibility_score.get("recommendation"),
            "suggested_status": _normalize_suggested_status(row.suggested_status or compatibility_score.get("suggested_status")) or row.suggested_status or compatibility_score.get("suggested_status"),
            "dimensions": sanitize_dimensions(compatibility_score.get("dimensions"), SCREENING_PAYLOAD_SCHEMA_CONFIG.get("score") or {}),
            "radar_scores": _sanitize_radar_scores(compatibility_score.get("radar_scores") or payload.get("radar_scores")),
            "manual_override_score": row.manual_override_score,
            "manual_override_reason": row.manual_override_reason,
            "hr_feedback": row.hr_feedback,
            "hr_feedback_reason": row.hr_feedback_reason,
            "created_at": isoformat_or_none(row.created_at),
            "updated_at": isoformat_or_none(row.updated_at),
        }

