    def _build_candidate_list_task_preload_maps(
        self,
        candidate_ids: Sequence[int],
    ) -> Tuple[Dict[int, Any], Dict[int, Any], Dict[int, Any], Dict[int, Any]]:
        normalized_candidate_ids = [int(candidate_id) for candidate_id in candidate_ids if candidate_id]
        if not normalized_candidate_ids:
            return {}, {}, {}, {}

        active_root_filter = and_(
            self._screening_root_task_filter(),
            RecruitmentAITaskLog.status.in_(SCREENING_LIVE_TASK_STATUSES),
        )
        completed_parse_filter = and_(
            RecruitmentAITaskLog.task_type == "resume_parse",
            RecruitmentAITaskLog.status == "success",
        )
        completed_score_filter = and_(
            self._screening_root_task_filter(),
            RecruitmentAITaskLog.status.in_(list(TERMINAL_AI_TASK_STATUSES)),
        )
        ai_match_filter = and_(
            RecruitmentAITaskLog.task_type == "ai_position_match",
            RecruitmentAITaskLog.status.in_(["success", "no_match", "failed"]),
        )
        task_category = case(
            (active_root_filter, "active_root"),
            (completed_parse_filter, "completed_parse"),
            (completed_score_filter, "completed_score"),
            (ai_match_filter, "ai_match"),
        )
        task_sort_at = case(
            (active_root_filter, RecruitmentAITaskLog.updated_at),
            else_=RecruitmentAITaskLog.created_at,
        )
        ranked_tasks = self.db.query(
            RecruitmentAITaskLog.id.label("id"),
            RecruitmentAITaskLog.related_candidate_id.label("related_candidate_id"),
            RecruitmentAITaskLog.related_position_id.label("related_position_id"),
            RecruitmentAITaskLog.screening_run_id.label("screening_run_id"),
            RecruitmentAITaskLog.task_type.label("task_type"),
            RecruitmentAITaskLog.stage.label("stage"),
            RecruitmentAITaskLog.status.label("status"),
            RecruitmentAITaskLog.created_at.label("created_at"),
            RecruitmentAITaskLog.updated_at.label("updated_at"),
            case(
                (or_(active_root_filter, ai_match_filter), RecruitmentAITaskLog.output_summary),
                else_=None,
            ).label("output_summary"),
            case(
                (active_root_filter, RecruitmentAITaskLog.output_snapshot),
                else_=None,
            ).label("output_snapshot"),
            case(
                (ai_match_filter, RecruitmentAITaskLog.parsed_response_json),
                else_=None,
            ).label("parsed_response_json"),
            case(
                (or_(active_root_filter, completed_score_filter), RecruitmentAITaskLog.validation_meta_json),
                else_=None,
            ).label("validation_meta_json"),
            task_category.label("task_category"),
            func.row_number().over(
                partition_by=(RecruitmentAITaskLog.related_candidate_id, task_category),
                order_by=(task_sort_at.desc(), RecruitmentAITaskLog.id.desc()),
            ).label("task_rank"),
        ).filter(
            RecruitmentAITaskLog.related_candidate_id.in_(normalized_candidate_ids),
            or_(active_root_filter, completed_parse_filter, completed_score_filter, ai_match_filter),
        ).subquery()
        latest_task_rows = self.db.query(
            ranked_tasks.c.id,
            ranked_tasks.c.related_candidate_id,
            ranked_tasks.c.related_position_id,
            ranked_tasks.c.screening_run_id,
            ranked_tasks.c.task_type,
            ranked_tasks.c.stage,
            ranked_tasks.c.status,
            ranked_tasks.c.created_at,
            ranked_tasks.c.updated_at,
            ranked_tasks.c.output_summary,
            ranked_tasks.c.output_snapshot,
            ranked_tasks.c.parsed_response_json,
            ranked_tasks.c.validation_meta_json,
            ranked_tasks.c.task_category,
        ).filter(ranked_tasks.c.task_rank == 1).all()

        active_root_map: Dict[int, Any] = {}
        completed_parse_map: Dict[int, Any] = {}
        completed_score_map: Dict[int, Any] = {}
        ai_match_map: Dict[int, Any] = {}
        category_maps = {
            "active_root": active_root_map,
            "completed_parse": completed_parse_map,
            "completed_score": completed_score_map,
            "ai_match": ai_match_map,
        }
        for task_row in latest_task_rows:
            target_map = category_maps.get(str(task_row.task_category or ""))
            candidate_id = int(task_row.related_candidate_id or 0)
            if target_map is None or not candidate_id:
                continue
            target_map[candidate_id] = SimpleNamespace(**dict(task_row._mapping))
        return active_root_map, completed_parse_map, completed_score_map, ai_match_map

    def _build_candidate_screening_state_summary(
        self,
        row: RecruitmentCandidate,
        *,
        _preloaded_active_root: Any = _UNSET,
        _preloaded_latest_completed_parse: Any = _UNSET,
        _preloaded_latest_completed_score: Any = _UNSET,
    ) -> Dict[str, Any]:
        if _preloaded_active_root is not _UNSET:
            active_root = _preloaded_active_root
        else:
            active_root = self.db.query(RecruitmentAITaskLog).filter(
                RecruitmentAITaskLog.related_candidate_id == row.id,
                self._screening_root_task_filter(),
                RecruitmentAITaskLog.status.in_(SCREENING_LIVE_TASK_STATUSES),
            ).order_by(
                RecruitmentAITaskLog.updated_at.desc(),
                RecruitmentAITaskLog.id.desc(),
            ).first()
            if active_root and active_root.status != "queued" and self._settle_orphaned_live_task(active_root):
                self.db.commit()
                active_root = self.db.query(RecruitmentAITaskLog).filter(
                    RecruitmentAITaskLog.related_candidate_id == row.id,
                    self._screening_root_task_filter(),
                    RecruitmentAITaskLog.status.in_(SCREENING_LIVE_TASK_STATUSES),
                ).order_by(
                    RecruitmentAITaskLog.updated_at.desc(),
                    RecruitmentAITaskLog.id.desc(),
                ).first()

        if _preloaded_latest_completed_parse is not _UNSET:
            latest_completed_parse_task = _preloaded_latest_completed_parse
        else:
            latest_completed_parse_task = self.db.query(RecruitmentAITaskLog).filter(
                RecruitmentAITaskLog.related_candidate_id == row.id,
                RecruitmentAITaskLog.task_type == "resume_parse",
                RecruitmentAITaskLog.status == "success",
            ).order_by(
                RecruitmentAITaskLog.created_at.desc(),
                RecruitmentAITaskLog.id.desc(),
            ).first()

        if _preloaded_latest_completed_score is not _UNSET:
            latest_completed_score_task = _preloaded_latest_completed_score
        else:
            latest_completed_score_task = self.db.query(RecruitmentAITaskLog).filter(
                RecruitmentAITaskLog.related_candidate_id == row.id,
                self._screening_root_task_filter(),
                RecruitmentAITaskLog.status.in_(list(TERMINAL_AI_TASK_STATUSES)),
            ).order_by(
                RecruitmentAITaskLog.created_at.desc(),
                RecruitmentAITaskLog.id.desc(),
            ).first()

        display_status_reason = None
        active_screening_auto_retry_scheduled = False
        active_screening_failure_code = None
        if active_root:
            active_snapshot = _decode_ai_task_json_text(active_root.output_snapshot, {}) if active_root.output_snapshot else {}
            active_validation = _decode_ai_task_json_text(active_root.validation_meta_json, {}) if active_root.validation_meta_json else {}
            parse_status = str((active_snapshot or {}).get("parse_status") or "").strip()
            reused_existing_parse = bool((active_snapshot or {}).get("reused_existing_parse"))
            parse_strategy = str(
                ((active_validation or {}).get("parse_strategy"))
                or ((active_snapshot or {}).get("parse_strategy"))
                or ""
            ).strip()
            failure_code = str(
                ((active_validation or {}).get("failure_code"))
                or ((active_snapshot or {}).get("failure_code"))
                or ""
            ).strip()
            active_screening_auto_retry_scheduled = bool(
                active_root.status == "queued"
                and ((active_validation or {}).get("auto_requeue_scheduled") or (active_snapshot or {}).get("auto_requeue_scheduled"))
            )
            active_screening_failure_code = failure_code or None
            if active_screening_auto_retry_scheduled:
                if failure_code == "rate_limited":
                    display_status_reason = "模型接口限流，系统将自动重试，请稍候。"
                elif failure_code == "upstream_timeout":
                    display_status_reason = "模型接口超时，系统将自动重试，请稍候。"
                else:
                    display_status_reason = str(active_root.output_summary or "系统已安排自动重试，请稍候。").strip() or "系统已安排自动重试，请稍候。"
            elif active_root.stage == "parsing" and reused_existing_parse:
                display_status_reason = "已复用解析结果，正在准备初筛评分"
            elif active_root.stage == "parsing":
                display_status_reason = "正在提取简历原文并准备 one-pass 初筛" if parse_strategy == "combined_parse_and_score" else "正在解析简历"
            elif active_root.stage == "scoring":
                display_status_reason = "已提取简历原文，正在执行 one-pass 初筛" if parse_strategy == "combined_parse_and_score" else "简历解析已完成，正在初筛评分"
            elif active_root.stage == "validating":
                display_status_reason = "评分已生成，正在校验结果"
            elif active_root.stage == "saving":
                display_status_reason = "评分校验已完成，正在写入最终结果"
            elif parse_status == "reused":
                display_status_reason = "已复用解析结果，初筛流程执行中"
            else:
                display_status_reason = "存在未结束的 screening_flow 任务"
        elif latest_completed_score_task and latest_completed_score_task.status in {"quota_exceeded", "retry_exhausted", "failed"}:
            latest_validation = _decode_ai_task_json_text(getattr(latest_completed_score_task, "validation_meta_json", None), {}) if latest_completed_score_task.validation_meta_json else {}
            latest_failure_code = str(
                ((latest_validation or {}).get("failure_code"))
                or ""
            ).strip()
            if latest_failure_code == "quota_exceeded":
                display_status_reason = "模型额度不足，请充值或更换模型后重试"
            elif latest_failure_code == "retry_exhausted":
                display_status_reason = "上游模型接口持续不可用，自动重试已达上限"

        return {
            "active_screening_run_id": active_root.screening_run_id if active_root else None,
            "active_screening_task_id": active_root.id if active_root else None,
            "active_screening_task_type": active_root.task_type if active_root else None,
            "active_screening_stage": active_root.stage if active_root else None,
            "active_screening_status": active_root.status if active_root else None,
            "active_screening_auto_retry_scheduled": active_screening_auto_retry_scheduled,
            "active_screening_failure_code": active_screening_failure_code,
            "active_screening_started_at": isoformat_or_none(active_root.created_at) if active_root else None,
            "latest_completed_parse_task_id": latest_completed_parse_task.id if latest_completed_parse_task else None,
            "latest_completed_score_task_id": latest_completed_score_task.id if latest_completed_score_task else None,
            "display_status_reason": display_status_reason,
        }

    def _build_direct_candidate_ai_match_snapshot(
        self,
        row: RecruitmentCandidate,
        *,
        include_alternatives: bool = True,
    ) -> Dict[str, Any]:
        return {
            "ai_match_position_id": getattr(row, "ai_match_position_id", None),
            "ai_match_position_title": getattr(row, "ai_match_position_title", None),
            "ai_match_confidence": getattr(row, "ai_match_confidence", None),
            "ai_match_reason": getattr(row, "ai_match_reason", None),
            "ai_match_alternatives": (
                json_loads_safe(getattr(row, "ai_match_alternatives", None), None)
                if include_alternatives
                else None
            ),
            "ai_potential_position": getattr(row, "ai_potential_position", None),
            "ai_potential_reason": getattr(row, "ai_potential_reason", None),
        }

    def _candidate_needs_ai_match_fallback(self, row: RecruitmentCandidate, snapshot: Dict[str, Any]) -> bool:
        if (
            str(getattr(row, "status", "") or "").strip() not in {"unmatched", "talent_pool"}
            and not getattr(row, "talent_pool_reason", None)
        ):
            return False
        return not (snapshot["ai_match_position_title"] and snapshot["ai_potential_position"])

    def _merge_candidate_ai_match_snapshot_from_log(
        self,
        row: RecruitmentCandidate,
        snapshot: Dict[str, Any],
        latest_match_log: Optional[RecruitmentAITaskLog],
        *,
        _preloaded_position: Any = _UNSET,
    ) -> Dict[str, Any]:
        if not latest_match_log:
            return snapshot

        parsed_response = _decode_ai_task_json_text(getattr(latest_match_log, "parsed_response_json", None), {})
        if not isinstance(parsed_response, dict):
            parsed_response = {}

        fallback_position_id = parsed_response.get("position_id")
        try:
            fallback_position_id = int(fallback_position_id) if fallback_position_id is not None and str(fallback_position_id).strip() else None
        except (TypeError, ValueError):
            fallback_position_id = None
        if fallback_position_id is None:
            fallback_position_id = getattr(latest_match_log, "related_position_id", None)

        fallback_position_title = str(parsed_response.get("position_title") or "").strip() or None
        if not fallback_position_title and fallback_position_id:
            fallback_position = _preloaded_position
            if fallback_position is _UNSET:
                fallback_position = self.db.query(RecruitmentPosition).filter(
                    RecruitmentPosition.id == fallback_position_id,
                    RecruitmentPosition.deleted.is_(False),
                ).first()
            fallback_position_title = fallback_position.title if fallback_position else None

        fallback_alternatives = parsed_response.get("alternatives")
        if not isinstance(fallback_alternatives, list):
            fallback_alternatives = None

        return {
            "ai_match_position_id": snapshot["ai_match_position_id"] if snapshot["ai_match_position_id"] is not None else fallback_position_id,
            "ai_match_position_title": snapshot["ai_match_position_title"] or fallback_position_title,
            "ai_match_confidence": snapshot["ai_match_confidence"] if snapshot["ai_match_confidence"] is not None else _parse_score_number(parsed_response.get("confidence")),
            "ai_match_reason": snapshot["ai_match_reason"] or (str(parsed_response.get("reason") or "").strip() or str(getattr(latest_match_log, "output_summary", "") or "").strip() or None),
            "ai_match_alternatives": snapshot["ai_match_alternatives"] if snapshot["ai_match_alternatives"] is not None else fallback_alternatives,
            "ai_potential_position": snapshot["ai_potential_position"] or (str(parsed_response.get("potential_position") or "").strip() or None),
            "ai_potential_reason": snapshot["ai_potential_reason"] or (str(parsed_response.get("potential_reason") or "").strip() or None),
        }

    def _build_candidate_ai_match_snapshot_map(
        self,
        rows: Sequence[RecruitmentCandidate],
        *,
        _preloaded_latest_match_logs: Any = _UNSET,
    ) -> Dict[int, Dict[str, Any]]:
        snapshot_map = {
            row.id: self._build_direct_candidate_ai_match_snapshot(row, include_alternatives=False)
            for row in rows
        }
        fallback_candidate_ids = [
            row.id
            for row in rows
            if self._candidate_needs_ai_match_fallback(row, snapshot_map[row.id])
        ]
        if not fallback_candidate_ids:
            return snapshot_map

        if _preloaded_latest_match_logs is not _UNSET:
            latest_match_logs = {
                candidate_id: log_row
                for candidate_id, log_row in _preloaded_latest_match_logs.items()
                if candidate_id in fallback_candidate_ids
            }
        else:
            latest_match_logs: Dict[int, RecruitmentAITaskLog] = {}
            log_rows = self.db.query(RecruitmentAITaskLog).filter(
                RecruitmentAITaskLog.related_candidate_id.in_(fallback_candidate_ids),
                RecruitmentAITaskLog.task_type == "ai_position_match",
                RecruitmentAITaskLog.status.in_(["success", "no_match", "failed"]),
            ).order_by(
                RecruitmentAITaskLog.related_candidate_id.asc(),
                RecruitmentAITaskLog.created_at.desc(),
                RecruitmentAITaskLog.id.desc(),
            ).all()
            for log_row in log_rows:
                candidate_id = int(log_row.related_candidate_id or 0)
                if candidate_id and candidate_id not in latest_match_logs:
                    latest_match_logs[candidate_id] = log_row

        fallback_position_ids: set[int] = set()
        fallback_parsed_payloads: Dict[int, Dict[str, Any]] = {}
        for candidate_id, log_row in latest_match_logs.items():
            parsed_response = _decode_ai_task_json_text(getattr(log_row, "parsed_response_json", None), {})
            if not isinstance(parsed_response, dict):
                parsed_response = {}
            fallback_parsed_payloads[candidate_id] = parsed_response
            fallback_position_id = parsed_response.get("position_id")
            try:
                fallback_position_id = int(fallback_position_id) if fallback_position_id is not None and str(fallback_position_id).strip() else None
            except (TypeError, ValueError):
                fallback_position_id = None
            if fallback_position_id is None:
                fallback_position_id = getattr(log_row, "related_position_id", None)
            fallback_position_title = str(parsed_response.get("position_title") or "").strip() or None
            if fallback_position_id and not fallback_position_title:
                fallback_position_ids.add(int(fallback_position_id))

        fallback_position_map: Dict[int, Any] = {}
        if fallback_position_ids:
            for position_row in self.db.query(
                RecruitmentPosition.id,
                RecruitmentPosition.title,
            ).filter(
                RecruitmentPosition.id.in_(fallback_position_ids),
                RecruitmentPosition.deleted.is_(False),
            ).all():
                fallback_position_map[position_row.id] = SimpleNamespace(
                    id=position_row.id,
                    title=position_row.title,
                )

        for row in rows:
            latest_match_log = latest_match_logs.get(row.id)
            if not latest_match_log:
                continue
            parsed_response = fallback_parsed_payloads.get(row.id) or {}
            fallback_position_id = parsed_response.get("position_id")
            try:
                fallback_position_id = int(fallback_position_id) if fallback_position_id is not None and str(fallback_position_id).strip() else None
            except (TypeError, ValueError):
                fallback_position_id = None
            if fallback_position_id is None:
                fallback_position_id = getattr(latest_match_log, "related_position_id", None)
            snapshot_map[row.id] = self._merge_candidate_ai_match_snapshot_from_log(
                row,
                snapshot_map[row.id],
                latest_match_log,
                _preloaded_position=fallback_position_map.get(int(fallback_position_id)) if fallback_position_id else None,
            )
        return snapshot_map

    def _resolve_candidate_ai_match_snapshot(self, row: RecruitmentCandidate) -> Dict[str, Any]:
        snapshot = self._build_direct_candidate_ai_match_snapshot(row)
        if not self._candidate_needs_ai_match_fallback(row, snapshot):
            return snapshot

        latest_match_log = self.db.query(RecruitmentAITaskLog).filter(
            RecruitmentAITaskLog.related_candidate_id == row.id,
            RecruitmentAITaskLog.task_type == "ai_position_match",
            RecruitmentAITaskLog.status.in_(["success", "no_match", "failed"]),
        ).order_by(
            RecruitmentAITaskLog.created_at.desc(),
            RecruitmentAITaskLog.id.desc(),
        ).first()
        return self._merge_candidate_ai_match_snapshot_from_log(row, snapshot, latest_match_log)

    def _build_candidate_list_display_payload(
        self,
        row: RecruitmentCandidate,
        *,
        _preloaded_score_row: Any = _UNSET,
        _preloaded_screening_state: Any = _UNSET,
        _preloaded_interview_state: Any = _UNSET,
    ) -> Dict[str, Any]:
        score_row = _preloaded_score_row if _preloaded_score_row is not _UNSET else (
            self.db.query(RecruitmentCandidateScore).filter(RecruitmentCandidateScore.id == row.latest_score_id).first()
            if row.latest_score_id else None
        )
        if score_row and getattr(score_row, "_candidate_list_projection", False):
            serialized_score = {
                "suggested_status": _normalize_suggested_status(score_row.suggested_status) or score_row.suggested_status,
                "match_percent": _parse_score_number(score_row.match_percent),
                "total_score": _parse_score_number(score_row.total_score),
            }
        else:
            serialized_score = self._serialize_score(score_row) if score_row else None
        screening_state = (_preloaded_screening_state if _preloaded_screening_state is not _UNSET else self._build_candidate_screening_state_summary(row)) or {}
        score_suggested_status = str(serialized_score.get("suggested_status") or "").strip() if serialized_score else ""
        ai_recommended_status = score_suggested_status or str(row.ai_recommended_status or "").strip() or None
        active_screening_auto_retry_scheduled = bool(screening_state.get("active_screening_auto_retry_scheduled"))
        if screening_state.get("active_screening_task_id") and not active_screening_auto_retry_scheduled:
            display_status = "screening_running"
        elif row.status == "pending_screening" and ai_recommended_status and not active_screening_auto_retry_scheduled:
            display_status = ai_recommended_status
        elif (
            row.status == "unmatched"
            and row.position_id
            and str(getattr(row, "talent_pool_reason", "") or "").strip() in {"auto_archived", "moved_by_hr"}
        ):
            display_status = "talent_pool"
        else:
            interview_state = _preloaded_interview_state
            if interview_state is _UNSET and str(row.status or "").strip() in INTERVIEW_DISPLAY_SOURCE_STATUSES:
                interview_state = self._build_interview_display_state_map([row.id]).get(row.id, {})
            elif interview_state is _UNSET:
                interview_state = {}
            interview_state = interview_state or {}
            display_status = self._resolve_interview_display_status(
                row.status,
                active_schedule=interview_state.get("active_schedule"),
                latest_completed_schedule=interview_state.get("latest_completed_schedule"),
            )
        return {
            "screening_state": screening_state,
            "display_status": display_status,
            "ai_recommended_status": ai_recommended_status,
            "display_match_percent": _parse_score_number(serialized_score.get("match_percent")) if serialized_score else _parse_score_number(row.match_percent),
            "display_total_score": _parse_score_number(serialized_score.get("total_score")) if serialized_score else _parse_score_number(score_row.total_score if score_row else None),
            "active_screening_auto_retry_scheduled": active_screening_auto_retry_scheduled,
        }

    def _serialize_candidate_summary(
        self,
        row: RecruitmentCandidate,
        *,
        _preloaded_position: Any = _UNSET,
        _preloaded_score_row: Any = _UNSET,
        _preloaded_screening_state: Any = _UNSET,
        _preloaded_interview_state: Any = _UNSET,
        _preloaded_skill_rows: Optional[Dict[str, List[RecruitmentSkill]]] = None,
    ) -> Dict[str, Any]:
        position = _preloaded_position if _preloaded_position is not _UNSET else (self.db.query(RecruitmentPosition).filter(RecruitmentPosition.id == row.position_id, RecruitmentPosition.deleted.is_(False)).first() if row.position_id else None)
        score_row = _preloaded_score_row if _preloaded_score_row is not _UNSET else (self.db.query(RecruitmentCandidateScore).filter(RecruitmentCandidateScore.id == row.latest_score_id).first() if row.latest_score_id else None)
        display_payload = self._build_candidate_list_display_payload(
            row,
            _preloaded_score_row=score_row,
            _preloaded_screening_state=_preloaded_screening_state,
            _preloaded_interview_state=_preloaded_interview_state,
        )
        screening_state = display_payload["screening_state"]
        ai_recommended_status = display_payload["ai_recommended_status"]
        display_status = display_payload["display_status"]
        display_match_percent = display_payload["display_match_percent"]
        display_total_score = display_payload["display_total_score"]
        active_screening_auto_retry_scheduled = display_payload["active_screening_auto_retry_scheduled"]
        if _preloaded_skill_rows is not None:
            position_screening_skill_rows = _preloaded_skill_rows.get("screening", [])
            position_interview_skill_rows = _preloaded_skill_rows.get("interview", [])
            position_jd_skill_rows = _preloaded_skill_rows.get("jd", [])
        else:
            position_screening_skill_rows = self._get_position_task_skill_rows(position.id, "screening") if position and self._is_business_row_visible(position) else []
            position_interview_skill_rows = self._get_position_task_skill_rows(position.id, "interview") if position and self._is_business_row_visible(position) else []
            position_jd_skill_rows = self._get_position_task_skill_rows(position.id, "jd") if position and self._is_business_row_visible(position) else []
        screened_position_title = position.title if position else None
        ai_match_snapshot = self._resolve_candidate_ai_match_snapshot(row)
